

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useQuery } from '@tanstack/react-query';
import { eventService } from '@/services/event-service';

const palette = {
  onyx: '#1C1C1B',
  obsidian: '#1a1a1a',
  walnut: '#6A5D52',
  greige: '#B7AC9B',
  ash: '#979086',
  stucco: '#E2E2DE',
  graphite: '#494947',
  gravel: '#7b787a'
};

export default function EventCatalogPage() {
  const router = useRouter();
  const [expandedId, setExpandedId] = useState<string | null>(null);

  // 🔥 KITA TARIK DATA ASLI DARI DATABASE LARAVEL 🔥
  const { data: events, isLoading } = useQuery({
    queryKey: ['events'],
    queryFn: eventService.getEvents,
  });

  if (isLoading) {
    return <div className="min-h-[60vh] flex items-center justify-center font-bold tracking-[0.3em] uppercase animate-pulse" style={{ color: palette.ash }}>ESTABLISHING CONNECTION...</div>;
  }

  return (
    <div className="relative py-12 min-h-screen bg-[#0a0a0a]">
      {/* <div className="fixed inset-0 z-0 pointer-events-none w-full h-full">
        <Beams
          beamWidth={3}
          beamHeight={30}
          beamNumber={20}
          lightColor={palette.greige}
          speed={2}
          noiseIntensity={1.75}
          scale={0.2}
          rotation={30}
        />
      </div> */}

      <div className="relative z-10 max-w-6xl mx-auto px-4">
        <button onClick={() => router.push('/dashboard')} className="cursor-pointer mb-12 font-bold text-xs tracking-[0.3em] uppercase transition-colors flex items-center gap-3 hover:text-white" style={{ color: palette.ash }}>
          <span className="w-8 h-[1px] block transition-all" style={{ backgroundColor: palette.ash }}></span> RETURN TO TERMINAL
        </button>

        <div className="mb-16">
          <p className="text-xs font-bold tracking-[0.3em] mb-4 uppercase" style={{ color: palette.greige }}>[ KATALOG EVENT ]</p>
          <h1 className="text-4xl md:text-6xl font-black mb-6 uppercase tracking-widest" style={{ color: palette.stucco }}>
            EVENTS
          </h1>
          <p className="text-lg font-medium tracking-widest max-w-2xl leading-relaxed uppercase" style={{ color: palette.ash }}>
            Ikuti berbagai rangkaian acara seru, workshop inspiratif, dan pameran karya spektakuler.
          </p>
        </div>

        {/* KALAU DATABASENYA KOSONG */}
        {!events || events.length === 0 ? (
          <div className="p-12 border text-center" style={{ backgroundColor: palette.onyx, borderColor: palette.graphite }}>
            <p className="font-bold tracking-[0.3em] uppercase" style={{ color: palette.ash }}>SYSTEM NOTICE: NO EVENT PROTOCOLS FOUND IN DATABASE.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {events.map((evt: any, idx: number) => {
              
              // LOGIKA OTOMATIS BERDASARKAN DATA ASLI LARAVEL
              const titleLower = evt.title.toLowerCase();
              const isPaid = Number(evt.price || 0) > 0;
              let badgeText = isPaid ? 'RESTRICTED WORKSHOP' : 'OPEN FREQUENCY (FREE)';
              let dotColor = isPaid ? palette.walnut : palette.ash; 
              
              if (titleLower.includes('show')) {
                badgeText = 'EXCLUSIVE EXHIBITION';
                dotColor = palette.stucco; 
              }

              const isOthersExpanded = expandedId !== null && expandedId !== evt.slug;

              return (
                <div 
                  key={evt.id} 
                  className={`group relative border p-8 flex flex-col transition-all duration-700 ease-[cubic-bezier(0.25,1,0.5,1)] 
                    ${isOthersExpanded ? 'opacity-30 scale-[0.97] blur-[2px] grayscale pointer-events-none' : 'hover:-translate-y-2'}`} 
                  style={{ 
                      backgroundColor: palette.onyx, 
                      borderColor: palette.graphite,
                      boxShadow: isOthersExpanded ? 'none' : '0 10px 30px -10px rgba(0,0,0,0.5)'
                  }}
                  onMouseEnter={(e) => { if(!isOthersExpanded) e.currentTarget.style.boxShadow = `0 20px 40px -15px ${palette.walnut}60` }}
                  onMouseLeave={(e) => { if(!isOthersExpanded) e.currentTarget.style.boxShadow = '0 10px 30px -10px rgba(0,0,0,0.5)' }}
                >
                  
                  <div className="flex justify-between items-center mb-8">
                    <div className="flex items-center gap-3 border px-4 py-2" style={{ borderColor: palette.graphite, backgroundColor: palette.obsidian }}>
                      <span className="w-2 h-2 rounded-full animate-pulse" style={{ backgroundColor: dotColor, boxShadow: `0 0 10px ${dotColor}` }}></span>
                      <span className="text-[9px] font-bold uppercase tracking-[0.2em]" style={{ color: palette.stucco }}>
                        {badgeText}
                      </span>
                    </div>
                    <span className="text-sm font-black tracking-widest" style={{ color: palette.ash }}>0{idx + 1}</span>
                  </div>
                  
                  <h2 className="text-2xl font-black uppercase tracking-widest mb-6 leading-tight" style={{ color: palette.stucco }}>{evt.title}</h2>
                  
                  <div className="mb-8 grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-[9px] tracking-[0.2em] mb-2 uppercase" style={{ color: palette.ash }}>CLEARANCE FEE</p>
                      <p className="text-lg font-black tracking-widest" style={{ color: isPaid ? palette.stucco : palette.greige }}>
                        {isPaid ? `Rp ${Number(evt.price).toLocaleString('id-ID')}` : 'NO CHARGE'}
                      </p>
                    </div>
                    <div>
                      <p className="text-[9px] tracking-[0.2em] mb-2 uppercase" style={{ color: palette.ash }}>CAPACITY</p>
                      <p className="text-sm font-bold tracking-widest mt-1 uppercase" style={{ color: evt.quota ? palette.stucco : palette.ash }}>
                        {evt.quota ? `${evt.quota} SLOTS LEFT` : 'UNLIMITED'}
                      </p>
                    </div>
                  </div>

                  <div className="flex-grow flex flex-col justify-end">
                    {expandedId === evt.slug ? (
                      <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 ease-[cubic-bezier(0.25,1,0.5,1)]">
                        <p className="text-sm leading-relaxed mb-8" style={{ color: palette.ash }}>
                          {evt.description || 'Information classified. Join the event to decrypt the full experience.'}
                        </p>
                        
                        <button 
                          // 🔥 SEKARANG NEMBAK PAKAI SLUG ASLI DARI LARAVEL 🔥
                          onClick={() => router.push(`/dashboard/event/${evt.slug}`)}
                          className="w-full py-5 font-black uppercase tracking-[0.2em] cursor-pointer transition-all duration-300 text-sm hover:scale-[1.03]"
                          style={{ backgroundColor: palette.stucco, color: palette.onyx, boxShadow: `0 0 15px ${palette.greige}40` }}
                        >
                          OBTAIN PASS
                        </button>

                        <button onClick={() => setExpandedId(null)} className="block w- cursor-pointer text-center mt-6 font-bold uppercase tracking-widest text-[10px] transition-colors" style={{ color: palette.gravel }}>
                          [ ABORT DETAIL VIEW ]
                        </button>
                      </div>
                    ) : (
                      <button onClick={() => setExpandedId(evt.slug)} className="w-full py-5 cursor-pointer font-bold uppercase tracking-[0.2em] text-xs border transition-all duration-300" style={{ color: palette.greige, borderColor: palette.graphite, backgroundColor: 'transparent' }} onMouseEnter={(e) => { e.currentTarget.style.backgroundColor = palette.greige; e.currentTarget.style.color = palette.onyx; }} onMouseLeave={(e) => { e.currentTarget.style.backgroundColor = 'transparent'; e.currentTarget.style.color = palette.greige; }}>
                        EXPAND PROTOCOL
                      </button>
                    )}
                  </div>

                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}